#!/usr/bin/env bash
# sis.sh — SIS 数据迁移与上线 SOP walkthrough for 教育SaaS.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="教育SaaS"
WORKFLOW="SIS 数据迁移与上线"

usage() {
  cat <<EOF
sis.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./sis.sh             # interactive
  ./sis.sh --dry-run
  ./sis.sh --json
  ./sis.sh --explain
  ./sis.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "SIS 数据迁移与上线" 工作流。

入门 SOP 共 7 步, 失败模式自检 3 项。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "数据盘点与清洗: 梳理现有数据字段（学生档案/教职工/课程/成绩/财务），识别脏数据，制定清洗规则 [T03-S015]"
  "映射设计: 将源字段映射到目标 SIS 数据模型（Ed-Fi/OneRoster标准），处理不兼容字段 [T03-S006]"
  "测试迁移: 用真实数据子集（约10%）做迁移演练，验证完整性和业务逻辑（计算GPA/学分规则等） [T03-S006]"
  "并行运行: 新旧系统并行运行4-8周，关键操作在两系统同步执行，比对差异 [T03-S015]"
  "全量迁移: 选低峰期（暑假/寒假）执行全量迁移，关闭旧系统写入权限 [T03-S006]"
  "验证与签收: 关键报表对比（学生数/课程数/成绩分布），stakeholder签收，迁移报告存档 [T03-S015]"
  "旧系统退役: 旧系统只读归档保留3-7年（合规要求），正式切换新系统为唯一权威数据源 [T03-S006]"
)
declare -a FAILURE_MODES=(
  "低估数据清洗工作量（通常占总项目工时40-60%），导致项目延期"
  "并行期太短（<4周），未覆盖完整业务周期（如成绩提交、报表生成）"
  "忽视接口系统（LMS/HR/财务）的同步更新，上线后数据孤岛"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "sis-walkthrough"
fi
